import{_ as p,o as e,c as a,j as r,a as t,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const h=JSON.parse('{"title":"宝可梦系列奇物","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/7.载具及随从/随从/7.系列随从/宝可梦系列/宝可梦系列奇物.md","filePath":"4.资源分区/7.物品与装备/7.载具及随从/随从/7.系列随从/宝可梦系列/宝可梦系列奇物.md"}'),s={name:"4.资源分区/7.物品与装备/7.载具及随从/随从/7.系列随从/宝可梦系列/宝可梦系列奇物.md"};function d(o,b,_,l,i,c){return e(),a("div",null,[...b[0]||(b[0]=[r("h1",{id:"宝可梦系列奇物",tabindex:"-1"},[t("宝可梦系列奇物 "),r("a",{class:"header-anchor",href:"#宝可梦系列奇物","aria-label":'Permalink to "宝可梦系列奇物"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：勿忘尘")])])],-1),n('<h1 id="宝可梦系列奇物-1" tabindex="-1">宝可梦系列奇物 <a class="header-anchor" href="#宝可梦系列奇物-1" aria-label="Permalink to &quot;宝可梦系列奇物&quot;">​</a></h1><p>宝可梦系列奇物<br> 特异本质<br> 所有此分类下属的物品皆为宝可梦专属奇物，不可对其他生物生效。有些特定的宝可梦技能可以使该装备转移到对手身上，届时该奇物的正面及负面特效同时生效。</p><p>【宝可梦营养饮料】</p><p>宝可梦营养饮料是在培育宝可梦的过程中，用于定向培养宝可梦的某方面能力而使用的消耗品，可以通过不同数量的营养饮料搭配来使宝可梦获得不同方向的成长，最终达成训练家对某只宝可梦特定的战术要求。<br> 每种宝可梦营养饮料的使用数量上限在其购买时有注明，单只宝可梦所能使用的营养饮料总数不得高于15瓶。</p><p>【HP增强剂】D+750<br> 一次性消耗品<br> 使用该营养药剂的宝可梦提高4点生命值上限，通过此种营养药剂所获得的生命值总数不得超过该宝可梦的原本的耐力值点数。</p><p>【攻击增强剂】1000<br> 一次性消耗品<br> 使用该营养药剂的宝可梦力量/敏捷获得3dp的增强加值，通过此种营养药剂所获得的增强加值总数不得超过该宝可梦原本的力量/敏捷点数。（在使用时选定其中一种属性，选定之后不可更改。）</p><p>【特攻增强剂】1000<br> 一次性消耗品<br> 使用该营养药剂的宝可梦智力/感知获得3dp的增强加值，通过此种营养药剂所获得的增强加值总数不得超过该宝可梦原本的智力/感知点数。（在使用时选定其中一种属性，选定之后不可更改。）</p><p>【防御增强剂】1000<br> 一次性消耗品<br> 使用该营养药剂的宝可梦获得3点天生防御，通过此种营养药剂所获得的天生防御总数不得超过该宝可梦原本的耐力/力量点数取高者。</p><p>【特防增强剂】1000<br> 一次性消耗品<br> 使用该营养药剂的宝可梦获得3点力场防御，通过此种营养药剂所获得的力场防御总数不得超过该宝可梦原本的耐力/感知点数取高者。</p><p>【速度增强剂】1000<br> 一次性消耗品<br> 使用该营养药剂的宝可梦获得6点先攻增强加值，通过此种营养药剂所获得的先攻增强加值总数不得超过该宝可梦原本的敏捷/沉着点数，两者取高。</p><p>【宝可梦药品】</p><p>宝可梦药品是专给宝可梦系列下属召唤物-宝可梦所使用的消耗品，不得对其他任何类型的生物使用。</p><p>宝可梦药品同样会产生药物疲劳。</p><p>【伤药】<br> 500<br> 一次性消耗品<br> 服用该消耗品的宝可梦可以在当前回合结束时恢复3点伤势。<br> 给不超过训练家自身触及范围的宝可梦喂伤药是一个标准动作，或者将伤药交给宝可梦装备，则该宝可梦在战斗中完好生命值低于自身生命值上限的一半时自动服用。<br> 若你在非战斗情况下给宝可梦服用伤药，宝可梦在经过15分钟的短休息后会恢复12点生命值至完好。</p><p>【灼伤药】/【解毒药】<br> 500<br> 一次性消耗品<br> 服用该消耗品的宝可梦清除6点燃烧/毒素点数，给不超过训练家自身触及范围的宝可梦喂【灼伤药】/【解毒药】是一个标准动作，或者将【灼伤药】/【解毒药】交给宝可梦装备，则该宝可梦在战斗中获得对应种类的异常点数时自动服用。</p><p>【解冻药】/【解麻药】<br> 500<br> 一次性消耗品<br> 服用该消耗品的宝可梦可清除6点冻结/麻痹点数，给不超过训练家自身触及范围的宝可梦喂【解冻药】/【解麻药】是一个标准动作，或者将【解冻药】/【解麻药】交给宝可梦装备，则该宝可梦在战斗中获得对应种类的异常点数时自动服用。</p><p>【好伤药】<br> 750<br> 一次性消耗品<br> 服用该消耗品的宝可梦可以在当前回合结束时恢复5点严重伤害至完好。给不超过训练家自身触及范围的宝可梦喂伤药是一个标准动作，或者将伤药交给宝可梦装备，则该宝可梦在战斗中完好生命值低于自身生命值上限的一半时自动服用。<br> 若你在非战斗情况下给宝可梦服用伤药，则宝可梦在进行短休息后恢复18点生命至完好。</p><p>【厉害伤药】<br> 1000<br> 一次性消耗品<br> 服用该消耗品的宝可梦可以在当前回合结束时恢复7点生命至完好。给不超过训练家自身触及范围的宝可梦喂伤药是一个标准动作，或者将伤药交给宝可梦装备，则该宝可梦在战斗中完好生命值低于自身生命值上限的一半时自动服用。<br> 若你在非战斗情况下给宝可梦服用伤药，则宝可梦在进行短休息后恢复24点生命至完好。</p><p>【万灵药】<br> 1500<br> 一次性消耗品<br> 服用该消耗品的宝可梦可以在本场景/10分钟内获得2点异常点数的恢复能力（医疗点48）。<br> 【不变之石】<br> 250</p><p>该奇物并非是宝可梦装备，不需要时时刻刻装备在宝可梦身上才能生效。<br> 购买不变之石后，当轮回者支付了足够的XP/道具后，宝可梦进行进化时，只需要在该宝可梦面前出示不变之石，则该宝可梦会立刻停止进化。然而这种停止进化仅限于外表及体型，其能力值会变成进化后的数值。<br> 例：轮回者支付xp以后，使小山猪进化为长毛猪，但进化过程中轮回者对小山猪出示了不变之石，则该小山猪的体型和外表不变，其他数值变为长毛猪的数值。即：小山猪其他属性变为长毛猪的属性，但体积仍为1，生命值为22，速度为24米。<br> 特别说明：使用不变之石对宝可梦的影响仅为外貌体积相关的影响，对其他方面无影响，即便轮回者支付了足够多的点数使小山猪进化为象牙猪，又使用不变之石取消了进化进程，但该小山猪仍无法满足进化奇石的使用条件。通俗地讲，主神空间中的不变之石仅是为了满足某些轮回者对某一形态的宝可梦的喜爱而生成的装扮类效果。</p><p>【要害攻击】<br> D+500<br> 一次性消耗品<br> 给宝可梦服用该消耗品消耗训练家一个标准动作。<br> 服用该消耗品的宝可梦的攻击检定获得等同于该宝可梦支线等级*4的附加成功（D1C2B3A4S5），持续一个场景。</p><p>【力量强化】<br> D+500<br> 一次性消耗品<br> 给宝可梦服用该消耗品消耗训练家一个标准动作。<br> 服用该消耗品的宝可梦的攻击检定可以获得等同于该宝可梦力量属性点的增强加值，持续一个场景。</p><p>【特攻强化】<br> D+500<br> 一次性消耗品<br> 给宝可梦服用该消耗品消耗训练家一个标准动作。<br> 服用该消耗品的宝可梦的攻击检定可以获得等同于该宝可梦智力属性点的增强加值，持续一个场景。</p><p>【速度强化】<br> 500<br> 一次性消耗品<br> 给宝可梦服用该消耗品消耗训练家一个标准动作。<br> 服用该消耗品的宝可梦的先攻权提高15点，持续一个场景。</p><p>【防御强化】<br> 500<br> 一次性消耗品<br> 给宝可梦服用该消耗品消耗训练家一个标准动作。<br> 服用该消耗品的宝可梦的天生防御提高8点，持续一个场景。</p><p>【特防强化】<br> 500<br> 一次性消耗品<br> 给宝可梦服用该消耗品消耗训练家一个标准动作。<br> 服用该消耗品的宝可梦的力场防御提高8点，持续一个场景。</p><p>【宝可梦进化石】<br> 用以让某些特定宝可梦进化的神奇石头，每种石头能够供给进化的宝可梦分别在各宝可梦的详细情报中叙述，不在此处赘述。<br> 每种进化石的价格皆为C+1000</p><p>【日之石】<br> 能让某些特定宝可梦进化的神奇石头，像太阳一样赤红。</p><p>【月之石】<br> 能让某些特定宝可梦进化的神奇石头，像夜空一样乌黑。</p><p>【火之石】<br> 能让某些特定宝可梦进化的神奇石头，看上去是橙黄色的。</p><p>【雷之石】<br> 能让某些特定宝可梦进化的神奇石头，有着闪电般的花纹。</p><p>【水之石】<br> 能让某些特定宝可梦进化的神奇石头，看上去是澄蓝色的。</p><p>【叶之石】<br> 能让某些特定宝可梦进化的神奇石头，有着叶子般的花纹。</p><p>【光之石】<br> 能让某些特定宝可梦进化的神奇石头，像光芒一样耀眼。</p><p>【暗之石】<br> 能让某些特定宝可梦进化的神奇石头，像黑夜一般漆黑。</p><p>【觉醒之石】<br> 能让某些特定宝可梦进化的神奇石头，像眼眸一般光彩动人。</p><p>【浑圆之石】<br> 能让某些特定宝可梦进化的神奇石头，像珠子一般圆润。</p><p>【宝可梦精灵球】<br> 用以抓捕宝可梦的道具，同时也是该宝可梦未来的住所。不同的精灵球拥有不同的特效，每只精灵球最多可供一个宝可梦居住。当精灵球中有宝可梦居住过之后视为已经绑定该宝可梦，之后不得更换为其他宝可梦。<br> 给宝可梦更换精灵球后，之前的精灵球视为弃用，主神空间不提供回收服务。</p><p>【豪华球】<br> 1000<br> 居住在豪华球中的宝可梦，每在其中经过4小时则增加5点亲密度。</p><p>【治愈球】<br> 1750<br> 居住在治愈球中的宝可梦，视为拥有1点快速医疗（医疗点12）。</p><p>【先机球】<br> 1750<br> 居住在先机球中的宝可梦在战斗中释放后，获得6点先攻加值。</p><p>【宝可梦装备】<br> 宝可梦在战斗中携带的装备，每只宝可梦最多装备一件装备。宝可梦装备无法给召唤物-宝可梦系列-宝可梦以外的生物装备。<br> 如果该宝可梦装备了药品，树果，消耗性道具，将同样视为装备了一件装备，占据唯一的装备位。</p><p>【光粉】<br> C+1000<br> 宝可梦装备<br> 携带光粉获得等同于宝可梦敏捷点数的闪避防御。</p><p>【突击背心】<br> C+1000<br> 宝可梦装备<br> 携带突击背心的宝可梦获得等同于宝可梦感知点数的力场防御，携带此装备的宝可梦无法使用变化类技能。</p><p>【讲究眼镜】<br> C+1000<br> 宝可梦装备<br> 携带讲究眼镜的宝可梦使用施法攻击检定时获得等同于宝可梦施法主属性点的增强加值，携带此装备的宝可梦每场战斗只能使用同一个技能，直到将其收回精灵球中。</p><p>【讲究头带】<br> C+1000<br> 宝可梦装备<br> 携带讲究头带的宝可梦使用物理系技能时获得等同于宝可梦力量属性点的增强加值，携带此装备的宝可梦每场战斗只能使用同一个技能，直到将其收回精灵球中。</p><p>【讲究围巾】<br> C+1000<br> 宝可梦装备<br> 携带讲究围巾的宝可梦的先攻获得等同于宝可梦敏捷点两倍的增强加值，携带此装备的宝可梦每场战斗只能使用同一个技能，直到将其收回精灵球中。</p><p>【火焰宝珠】<br> 50<br> 宝可梦装备<br> 携带火焰宝珠的宝可梦每轮受到1点不可豁免的燃烧点数（附身来源），该燃烧点数不可叠加。</p><p>【剧毒宝珠】<br> 50<br> 宝可梦装备<br> 携带剧毒宝珠的宝可梦受到1点不可豁免的毒素点数（附身来源），该毒素点数不可叠加。</p><p>【生命宝珠】<br> D+500<br> 宝可梦装备<br> 携带生命宝珠的宝可梦在使用攻击检定时获得等于该攻击检定使用的主属性点数一半的增强加值，且每次使用技能承受等于该主属性点1/4不可避免的严重伤害（向下取整）。</p><p>【气势批带】<br> 宝可梦装备<br> D+500<br> 一次性消耗品<br> 携带气势批带的宝可梦受到会直接杀死宝可梦的伤害时，抵消这一伤害，这是一个C级命运来源的无敌效果。这一效果对每个宝可梦而言一影片只能触发一次，即使你多次装备其他气势批带也是如此。</p><p>【气势头带】<br> 宝可梦装备<br> D+500<br> 携带气势头带的宝可梦，在不拥有伤势的状态下承受一次足以致死的伤害时骰一个D10自然骰，若结果为10（该自然骰不得以任何能力重骰或增幅），则抵消该次伤害，这是一个D级命运来源的无敌效果。这一无敌效果对每个宝可梦而言一影片只能触发一次，即使你多次装备其他气势头带也是如此。当无敌效果触发一次以后，气势头带会在本影片内失去作用。</p><p>【对焦镜】<br> 1000<br> 宝可梦装备<br> 携带对焦镜的宝可梦，在对先攻比自己高的对手进行攻击判定时获得等同于该宝可梦支线等级的DP加值（D1C2B3A4S5）。</p><p>【节拍器】<br> C+1000<br> 宝可梦装备<br> 携带节拍器的宝可梦，在使用同一种宝可梦技能时，获得等同于本场景内已使用次数x2的附加成功（第一次0、第二次2、第三次4、第四次6……）。若宝可梦不再使用同一种技艺，则该效果重新计算。</p><p>【后攻之尾】<br> 250<br> 宝可梦装备<br> 携带后攻之尾的宝可梦的先攻投掷降低至0，默认处于先攻列表的最后一位。</p><p>【附着针】<br> C+1000<br> 宝可梦装备<br> 携带附着针的单位每回合行动结束后受到等同于自身耐力属性点的穿刺严重伤害，强韧豁免。特殊的，这一物品如果被其他单位携带，也可正常生效。从身上拔出附着针是一个标准动作。</p><p>【大根茎】<br> C+1000<br> 宝可梦装备<br> 携带大根茎的宝可梦获得等同于该宝可梦支线等级两倍的吸血点数（D1C2B3A4S5）。</p><p>【进化奇石】<br> B+2000<br> 宝可梦装备<br> 携带进化奇石的宝可梦，携带者若是还能进化的宝可梦便会获得等同于该宝可梦感知属性点的力场防御以及1点基于力场防御的附加成功和等同于耐力属性点的天生防御以及1点基于天生防御的附加成功。<br> 特别说明：还能进化的宝可梦指的是还拥有一般进化型的宝可梦，Mega进化和极巨化不包含在本效果的前提中。</p><p>【凸凸头盔】<br> C+1000<br> 宝可梦装备<br> 携带凸凸头盔的宝可梦每次承受近战攻击时，对攻击来源造成等同于本次伤害1/4的钝击伤害，至多8点。</p><p>【气球】<br> 100<br> 宝可梦装备<br> 一次性消耗品（？）<br> 携带气球的宝可梦可以迅捷动作放出气球令自己漂浮于距地面垂直1米高度的空中，受到任意类型和来源的伤害后破裂，失去原本效果。处于漂浮的宝可梦可能会躲开一些仅作用于地面的效果。<br> 若宝可梦处于漂浮状态将无法移动，除非其具有飞行能力。<br> 松开气球令自己回到地面也是一个迅捷动作，这意味着气球会飞走，若无法取回即视为丢失。<br> 特别说明：此效果不等同于该宝可梦获得了飞行能力，仅能使宝可梦漂浮起来。</p><p>【紧绑束带】<br> C+1000<br> 宝可梦装备<br> 携带了紧绑束带的宝可梦在使用会造成纠缠点数的技能时，额外对对手造成3点不可豁免的纠缠点数，纠缠点数为附身来源。</p><p>【火/水/电/草/冰/毒/虫/钢/恶/地面/飞行/岩石/幽灵/一般/妖精/格斗/超能力宝石】<br> 1000<br> 宝可梦装备 一次性消耗品<br> 携带了某种属性的宝石的宝可梦，在使用和该宝石属性相同的技能时，该技能获得等同于该宝可梦攻击检定主属性点的能量加值。效果生效一次后，宝石毁坏且无法以任何办法复原。</p><p>【火/水/电/草/冰/毒/虫/钢/恶/地面/飞行/岩石/幽灵/一般/妖精/格斗/超能力石板】<br> D+750<br> 宝可梦装备<br> 携带了某种属性的石板的宝可梦，在使用和该石板属性相同的技能时，该技能获得等同于该宝可梦攻击检定主属性点一半的能量加值（向下取整）。</p><p>【逃脱按键】<br> D+500<br> 宝可梦装备<br> 携带了逃脱按键的宝可梦，在受到一次任意来源的伤害后，立刻回到精灵球中与后备任意一只宝可梦进行替换，回收距离不得超过训练家的45米范围。该效果无法在训练家没有后备宝可梦时生效。<br> 这一效果一场景仅生效一次。</p><p>【弱点保险】<br> C+1000<br> 宝可梦装备<br> 携带了弱点保险的宝可梦，若具有某种【易伤】点数并在某次受到伤害时触发了该【易伤】，则该宝可梦的物理系技能获得等同于该宝可梦力量属性点的增强加值且施法攻击检定获得等同于该宝可梦施法检定主属性点的能量加值，持续一场景，这一效果回收至精灵球后失效，该效果每场景触发一次。</p><p>【吃剩的东西】<br> C+1000<br> 宝可梦装备<br> 携带了吃剩的东西的宝可梦，获得等同于耐力属性的附加成功数两倍的快速医疗点数（医疗点72）。</p><p>【厚底靴】<br> C+1000<br> 宝可梦装备<br> 携带厚底靴的宝可梦免疫B级及以下的困难地形效果，并可以免疫B级及以下的、基于地面作用的环境来源的负面效果。（例如灌木丛、荆棘、碎石堆、冰原、密林、吃人沼泽等）</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',69)])])}const D=p(s,[["render",d]]);export{h as __pageData,D as default};
